#include <stdio.h>
#include <stdlib.h>
#define MAX 200
#define MIN 1

int** pacificAtlantic(int** matrix, int matrixSize, int* matrixColSize, int* returnSize) {
    if (matrixSize == 0 || matrixColSize[0] == 0) return NULL;
    int m = matrixSize;
    int n = matrixColSize[0];
    int** result = (int**)malloc(sizeof(int*) * m * n);
    *returnSize = 0;
    int** visited = (int**)malloc(sizeof(int*) * m);
    for (int i = 0; i < m; i++) {
        visited[i] = (int*)malloc(sizeof(int) * n);
        for (int j = 0; j < n; j++) {
            visited[i][j] = 0;
        }
    }
    for (int i = 0; i < m; i++) {
        dfs(matrix, i, 0, visited, m, n);
        dfs(matrix, i, n - 1, visited, m, n);
    }
    for (int i = 0; i < n; i++) {
        dfs(matrix, 0, i, visited, m, n);
        dfs(matrix, m - 1, i, visited, m, n);
    }
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (visited[i][j] == 3) {
                result[(*returnSize)++] = (int*)malloc(sizeof(int) * 2);
                result[(*returnSize) - 1][0] = i;
                result[(*returnSize) - 1][1] = j;
            }
        }
    }
    return result;
}

void dfs(int** matrix, int x, int y, int** visited, int m, int n) {
    if (x < 0 || x >= m || y < 0 || y >= n || visited[x][y] == 3) return;
    visited[x][y] |= 1;
    if (x > 0 && matrix[x - 1][y] >= matrix[x][y]) dfs(matrix, x - 1, y, visited, m, n);
    if (x < m - 1 && matrix[x + 1][y] >= matrix[x][y]) dfs(matrix, x + 1, y, visited, m, n);
    if (y > 0 && matrix[x][y - 1] >= matrix[x][y]) dfs(matrix, x, y - 1, visited, m, n);
    if (y < n - 1 && matrix[x][y + 1] >= matrix[x][y]) dfs(matrix, x, y + 1, visited, m, n);
}

