        dfs(matrix, 0, i, pacific);
        dfs(matrix, m - 1, i, atlantic);
    }
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (pacific[i][j] && atlantic[i][j]) {
                result.push_back({i, j});
            }
        }
    }
    return result;
}

void dfs(vector<vector<int>>& matrix, int x, int y, vector<vector<bool>>& visited) {
    if (x < 0 || x >= matrix.size() || y < 0 || y >= matrix[0].size() || visited[x][y]) return;
    visited[x][y] = true;
    if (x > 0 && matrix[x - 1][y] >= matrix[x][y]) dfs(matrix, x - 1, y, visited);
    if (x < matrix.size() - 1 && matrix[x + 1][y] >= matrix[x][y]) dfs(matrix, x + 1, y, visited);
    if (y > 0 && matrix[x][y - 1] >= matrix[x][y]) dfs(matrix, x, y - 1, visited);
    if (y < matrix[0].size() - 1 && matrix[x][y + 1] >= matrix[x][y]) dfs(matrix, x, y + 1, visited);
}

