public class Solution {
    public List<List<Integer>> pacificAtlantic(int[][] matrix) {
        if (matrix.length == 0 || matrix[0].length == 0) return new ArrayList<>();
        int m = matrix.length;
        int n = matrix[0].length;
        boolean[][] pacific = new boolean[m][n];
        boolean[][] atlantic = new boolean[m][n];
        for (int i = 0; i < m; i++) {
            dfs(matrix, i, 0, pacific);
            dfs(matrix, i, n - 1, atlantic);
        }
        for (int i = 0; i < n; i++) {
            dfs(matrix, 0, i, pacific);
            dfs(matrix, m - 1, i, atlantic);
        }
        List<List<Integer>> result = new ArrayList<>();
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (pacific[i][j] && atlantic[i][j]) {
                    result.add(Arrays.asList(i, j));
                }
            }
        }
        return result;
    }

    private void dfs(int[][] matrix, int x, int y, boolean[][] visited) {
        if (x < 0 || x >= matrix.length || y < 0 || y >= matrix[0].length || visited[x][y]) return;
        visited[x][y] = true;
        if (x > 0 && matrix[x - 1][y] >= matrix[x][y]) dfs(matrix, x - 1, y, visited);
        if (x < matrix.length - 1 && matrix[x + 1][y] >= matrix[x][y]) dfs(matrix, x + 1, y, visited);
        if (y > 0 && matrix[x][y - 1] >= matrix[x][y]) dfs(matrix, x, y - 1, visited);
        if (y < matrix[0].length - 1 && matrix[x][y + 1] >= matrix[x][y]) dfs(matrix, x, y + 1, visited);
    }
}

